data class Product(val id: Int, val name: String, val price: Double)

fun main() {
    val product = Product(1, "Laptop", 999.99)
    val kClass = product::class

    println("Class: ${kClass.simpleName}")
    println("Constructors: ${kClass.constructors.size}")

    kClass.memberProperties.forEach { prop ->
        println("${prop.name}: ${prop.get(product)}")
    }

    // Callable reference
    val toStr: (Product) -> String = Product::toString
    println(toStr(product))
}
